1	//! 稳定符号 ID 系统
2	//!
3	//! 基于 blake3 指纹的稳定符号标识符，格式为：
4	//! `language::relative_path::kind::name::fingerprint`
5	//!
6	//! 其中 fingerprint 为 `name + path + language + kind` 串联后
7	//! blake3 哈希的前 8 字符（前 4 字节）。
8	
9	use serde::{Deserialize, Serialize};
10	
11	/// 稳定符号 ID
12	///
13	/// 由语言、路径、符号类型、名称和 blake3 指纹组成。
14	/// 指纹确保即使符号重命名或移动后也能通过原始属性查找到。
15	#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
16	pub struct StableSymbolId {
17	    /// 编程语言（rust, typescript, java 等）
18	    pub language: String,
19	    /// 相对于项目根目录的文件路径
20	    pub relative_path: String,
21	    /// 符号类型
22	    pub kind: String,
23	    /// 符号名称
24	    pub name: String,
25	    /// blake3 指纹（8 字符十六进制）
26	    pub fingerprint: String,
27	}
28	
29	impl StableSymbolId {
30	    /// 创建新的稳定符号 ID
31	    ///
32	    /// 自动计算 blake3 指纹。
33	    pub fn new(language: &str, relative_path: &str, kind: &str, name: &str) -> Self {
34	        let fingerprint = Self::compute_fingerprint(language, relative_path, kind, name);
35	        Self {
36	            language: language.to_string(),
37	            relative_path: relative_path.to_string(),
38	            kind: kind.to_string(),
39	            name: name.to_string(),
40	            fingerprint,
41	        }
42	    }
43	
44	    /// 计算 blake3 指纹
45	    ///
46	    /// 输入格式：`name::path::language::kind`
47	    /// 输出：前 4 字节的十六进制表示（8 字符）
48	    fn compute_fingerprint(language: &str, path: &str, kind: &str, name: &str) -> String {
49	        let input = format!("{}::{}::{}::{}", name, path, language, kind);
50	        let hash = blake3::hash(input.as_bytes());
51	        // 取前 4 字节 = 8 个十六进制字符
52	        hex::encode(&hash.as_bytes()[..4])
53	    }
54	
55	    /// 序列化为存储格式字符串
56	    ///
57	    /// 格式：`language::relative_path::kind::name::fingerprint`
58	    pub fn to_storage_string(&self) -> String {
59	        format!(
60	            "{}::{}::{}::{}::{}",
61	            self.language, self.relative_path, self.kind, self.name, self.fingerprint
62	        )
63	    }
64	
65	    /// 从字符串解析稳定符号 ID
66	    ///
67	    /// 期望格式：`language::relative_path::kind::name::fingerprint`
68	    /// 5 个以 `::` 分隔的字段。
69	    pub fn parse(s: &str) -> Result<Self, String> {
70	        let parts: Vec<&str> = s.split("::").collect();
71	        if parts.len() != 5 {
72	            return Err(format!("无效的符号 ID 格式，期望 5 个字段实际得到 {} 个: {}", parts.len(), s));
73	        }
74	        Ok(Self {
75	            language: parts[0].into(),
76	            relative_path: parts[1].into(),
77	            kind: parts[2].into(),
78	            name: parts[3].into(),
79	            fingerprint: parts[4].into(),
80	        })
81	    }
82	}
83	
84	// ============================================================================
85	// 标准 trait 实现
86	// ============================================================================
87	
88	impl std::fmt::Display for StableSymbolId {
89	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
90	        write!(f, "{}", self.to_storage_string())
91	    }
92	}
93	
94	impl std::str::FromStr for StableSymbolId {
95	    type Err = String;
96	
97	    fn from_str(s: &str) -> Result<Self, Self::Err> {
98	        Self::parse(s)
99	    }
100	}
101	
102	// ============================================================================
103	// 测试
104	// ============================================================================
105	
106	#[cfg(test)]
107	mod tests {
108	    use super::*;
109	
110	    #[test]
111	    fn test_create_stable_id() {
112	        let id = StableSymbolId::new("rust", "src/main.rs", "function", "main");
113	        assert_eq!(id.language, "rust");
114	        assert_eq!(id.relative_path, "src/main.rs");
115	        assert_eq!(id.kind, "function");
116	        assert_eq!(id.name, "main");
117	        assert_eq!(id.fingerprint.len(), 8);
118	    }
119	
120	    #[test]
121	    fn test_fingerprint_is_stable() {
122	        let id1 = StableSymbolId::new("rust", "src/main.rs", "function", "main");
123	        let id2 = StableSymbolId::new("rust", "src/main.rs", "function", "main");
124	        assert_eq!(id1.fingerprint, id2.fingerprint);
125	    }
126	
127	    #[test]
128	    fn test_fingerprint_differs() {
129	        let id1 = StableSymbolId::new("rust", "src/main.rs", "function", "main");
130	        let id2 = StableSymbolId::new("rust", "src/main.rs", "function", "other");
131	        assert_ne!(id1.fingerprint, id2.fingerprint);
132	    }
133	
134	    #[test]
135	    fn test_to_string_and_parse() {
136	        let original = StableSymbolId::new("typescript", "src/components/App.tsx", "class", "App");
137	        let serialized = original.to_string();
138	        let parsed = StableSymbolId::from_str(&serialized).unwrap();
139	        assert_eq!(original, parsed);
140	    }
141	
142	    #[test]
143	    fn test_parse_invalid_format() {
144	        let result = StableSymbolId::from_str("too::few::fields");
145	        assert!(result.is_err());
146	    }
147	}
