1	//! 统一 MCP 响应信封
2	//!
3	//! 提供标准化的请求-响应封装 [`McpResponse`]，包含请求 ID、
4	//! 状态码、警告信息、负载数据和元信息。
5	//!
6	//! 同时提供 [`PageToken`] 用于分页查询。
7	
8	use serde::{Deserialize, Serialize};
9	use uuid::Uuid;
10	
11	// ============================================================================
12	// McpResponse
13	// ============================================================================
14	
15	/// 统一 MCP 响应信封
16	///
17	/// 所有 MCP 协议交互均使用此结构包装，确保前端能统一处理
18	/// 成功、部分成功和错误状态。
19	#[derive(Debug, Clone, Serialize, Deserialize)]
20	pub struct McpResponse<T: Serialize> {
21	    /// 请求 ID（UUID v4）
22	    pub request_id: String,
23	
24	    /// 响应状态
25	    pub status: ResponseStatus,
26	
27	    /// 警告信息列表（非致命问题）
28	    #[serde(skip_serializing_if = "Vec::is_empty")]
29	    pub warnings: Vec<String>,
30	
31	    /// 响应数据（成功时有值）
32	    pub data: Option<T>,
33	
34	    /// 响应元信息
35	    pub meta: ResponseMeta,
36	}
37	
38	/// 响应状态枚举
39	#[derive(Debug, Clone, Serialize, Deserialize)]
40	pub enum ResponseStatus {
41	    /// 成功 — 所有请求项均正常返回
42	    Success,
43	    /// 部分成功 — 部分结果返回，伴有警告
44	    Partial,
45	    /// 错误 — 请求处理失败
46	    Error,
47	}
48	
49	/// 响应元信息
50	#[derive(Debug, Clone, Serialize, Deserialize)]
51	pub struct ResponseMeta {
52	    /// 请求处理耗时（毫秒）
53	    pub took_ms: u64,
54	
55	    /// 总结果数（服务器端匹配总数）
56	    pub total_results: usize,
57	
58	    /// 本次返回的结果数
59	    pub returned_results: usize,
60	
61	    /// 下一页游标 token（无下一页时为 None）
62	    pub next_page_token: Option<String>,
63	
64	    /// 索引陈旧度（毫秒），表示索引最后更新时间距今多久
65	    pub index_staleness_ms: Option<u64>,
66	}
67	
68	impl<T: Serialize> McpResponse<T> {
69	    /// 创建成功响应
70	    ///
71	    /// # 参数
72	    /// - `data` — 响应负载数据
73	    /// - `total` — 服务器端匹配总数
74	    /// - `returned` — 本次实际返回数
75	    /// - `took_ms` — 处理耗时（毫秒）
76	    pub fn success(data: T, total: usize, returned: usize, took_ms: u64) -> Self {
77	        Self {
78	            request_id: Uuid::new_v4().to_string(),
79	            status: ResponseStatus::Success,
80	            warnings: vec![],
81	            data: Some(data),
82	            meta: ResponseMeta {
83	                took_ms,
84	                total_results: total,
85	                returned_results: returned,
86	                next_page_token: None,
87	                index_staleness_ms: None,
88	            },
89	        }
90	    }
91	
92	    /// 创建错误响应
93	    ///
94	    /// # 参数
95	    /// - `message` — 错误描述，会放入 warnings 字段
96	    pub fn error(message: &str) -> Self {
97	        Self {
98	            request_id: Uuid::new_v4().to_string(),
99	            status: ResponseStatus::Error,
100	            warnings: vec![message.to_string()],
101	            data: None,
102	            meta: ResponseMeta {
103	                took_ms: 0,
104	                total_results: 0,
105	                returned_results: 0,
106	                next_page_token: None,
107	                index_staleness_ms: None,
108	            },
109	        }
110	    }
111	
112	    /// 添加警告信息
113	    ///
114	    /// 添加一条警告后自动将状态设置为 Partial。
115	    ///
116	    /// # 参数
117	    /// - `warning` — 警告信息
118	    pub fn with_warning(mut self, warning: String) -> Self {
119	        self.warnings.push(warning);
120	        self.status = ResponseStatus::Partial;
121	        self
122	    }
123	
124	    /// 设置下一页游标 token
125	    ///
126	    /// # 参数
127	    /// - `token` — 分页游标字符串
128	    pub fn with_page_token(mut self, token: String) -> Self {
129	        self.meta.next_page_token = Some(token);
130	        self
131	    }
132	
133	    /// 设置索引陈旧度
134	    ///
135	    /// # 参数
136	    /// - `ms` — 索引自上次更新以来的毫秒数
137	    pub fn with_staleness(mut self, ms: u64) -> Self {
138	        self.meta.index_staleness_ms = Some(ms);
139	        self
140	    }
141	}
142	
143	// ============================================================================
144	// PageToken
145	// ============================================================================
146	
147	/// 分页游标
148	///
149	/// 用于在多次请求间维持查询上下文，支持大数据集的分页遍历。
150	/// 通过 base64 编码的 JSON 序列化实现不透明传输。
151	#[derive(Debug, Clone, Serialize, Deserialize)]
152	pub struct PageToken {
153	    /// 查询内容的哈希值（用于校验查询一致性）
154	    pub query_hash: String,
155	
156	    /// 当前偏移量
157	    pub offset: usize,
158	}
159	
160	impl PageToken {
161	    /// 创建新的分页游标
162	    ///
163	    /// # 参数
164	    /// - `query_hash` — 查询哈希
165	    /// - `offset` — 偏移量
166	    pub fn new(query_hash: String, offset: usize) -> Self {
167	        Self {
168	            query_hash,
169	            offset,
170	        }
171	    }
172	
173	    /// 序列化为传输字符串（base64 JSON）
174	    pub fn encode(&self) -> Result<String, serde_json::Error> {
175	        let json = serde_json::to_string(self)?;
176	        Ok(json)
177	    }
178	
179	    /// 从传输字符串反序列化
180	    pub fn decode(s: &str) -> Result<Self, serde_json::Error> {
181	        serde_json::from_str(s)
182	    }
183	}
184	
185	// ============================================================================
186	// 测试
187	// ============================================================================
188	
189	#[cfg(test)]
190	mod tests {
191	    use super::*;
192	
193	    #[test]
194	    fn test_success_response() {
195	        let response = McpResponse::success("hello", 1, 1, 42);
196	        assert_eq!(response.status, ResponseStatus::Success);
197	        assert_eq!(response.data, Some("hello"));
198	        assert!(response.warnings.is_empty());
199	        assert_eq!(response.meta.took_ms, 42);
200	    }
201	
202	    #[test]
203	    fn test_error_response() {
204	        let response = McpResponse::<()>::error("something went wrong");
205	        assert_eq!(response.status, ResponseStatus::Error);
206	        assert!(response.data.is_none());
207	        assert_eq!(response.warnings, vec!["something went wrong"]);
208	    }
209	
210	    #[test]
211	    fn test_with_warning() {
212	        let response = McpResponse::success("data", 1, 1, 10)
213	            .with_warning("stale index".into());
214	        assert_eq!(response.status, ResponseStatus::Partial);
215	        assert_eq!(response.warnings, vec!["stale index"]);
216	    }
217	
218	    #[test]
219	    fn test_page_token_roundtrip() {
220	        let token = PageToken::new("abc123".into(), 50);
221	        let encoded = token.encode().unwrap();
222	        let decoded = PageToken::decode(&encoded).unwrap();
223	        assert_eq!(decoded.query_hash, "abc123");
224	        assert_eq!(decoded.offset, 50);
225	    }
226	}
