14	use std::path::{Path, PathBuf};
15	use std::sync::Arc;
16	use std::time::SystemTime;
17	
18	use crossbeam::channel;
19	use rayon::prelude::*;
20	
21	use codeconnect_core::error::CodeConnectError;
22	use codeconnect_core::types::{FileMeta, SymbolKind};
23	use codeconnect_parser::factory::ParserRegistry;
24	use ignore::WalkBuilder;
25	
26	use crate::sled_store::SledStore;
27	use crate::tantivy_index::{TantivyIndex, CURRENT_SCHEMA_VERSION};
28	
