1	//! 循环依赖检测
2	//!
3	//! 使用 Kosaraju SCC 算法检测代码库中的循环依赖，
4	//! 支持拓扑排序输出。
5	//!
6	//! # 核心方法
7	//!
8	//! - `detect_cycles` — 找出所有强连通分量（SCC），过滤掉单节点分量，
9	//!   剩余的就是循环依赖
10	//! - `has_cycle` — 快速判断图中是否存在循环依赖
11	//! - `topological_order` — 对依赖图做拓扑排序，存在循环时返回参与循环的节点
12	//!
13	//! # 示例
14	//!
15	//! ```ignore
16	//! use codeconnect_graph::cycle_detect::CycleDetector;
17	//! use codeconnect_graph::dep_graph::DependencyGraph;
18	//!
19	//! let graph = DependencyGraph::build_file_graph(&sled_store)?;
20	//! let cycles = CycleDetector::detect_cycles(&graph);
21	//! if !cycles.is_empty() {
22	//!     for cycle in &cycles {
23	//!         eprintln!("发现循环依赖: {:?}", cycle.iter().map(|n| &n.id).collect::<Vec<_>>());
24	//!     }
25	//! }
26	//! ```
27	
28	use petgraph::algo::{kosaraju_scc, toposort};
29	
30	use super::dep_graph::{DepNode, DependencyGraph};
31	
32	/// 循环依赖检测器
33	///
34	/// 基于 petgraph 的 Kosaraju SCC 算法进行强连通分量检测，
35	/// 通过在 petgraph 图中标记节点顺序来实现拓扑排序。
36	pub struct CycleDetector;
37	
38	impl CycleDetector {
39	    /// 检测依赖图中的所有循环依赖
40	    ///
41	    /// 使用 Kosaraju SCC 算法找出所有强连通分量，
42	    /// 过滤掉单节点分量（单独节点不构成循环，除非自环），
43	    /// 返回多节点的 SCC 列表，每个 SCC 是一个循环依赖。
44	    pub fn detect_cycles(graph: &DependencyGraph) -> Vec<Vec<DepNode>> {
45	        let inner = graph.inner_graph();
46	
47	        // 使用 Kosaraju 算法找出所有强连通分量
48	        let sccs = kosaraju_scc(inner);
49	
50	        // 过滤：只保留多节点分量（至少2个节点的 SCC 才构成循环依赖）
51	        sccs
52	            .into_iter()
53	            .filter(|scc| scc.len() > 1)
54	            .map(|scc| {
55	                scc.into_iter()
56	                    .map(|node_idx| inner[node_idx].clone())
57	                    .collect()
58	            })
59	            .collect()
60	    }
61	
62	    /// 检查依赖图中是否存在循环依赖
63	    ///
64	    /// 返回 `true` 表示图中存在至少一个多节点 SCC。
65	    pub fn has_cycle(graph: &DependencyGraph) -> bool {
66	        let inner = graph.inner_graph();
67	        let sccs = kosaraju_scc(inner);
68	        sccs.iter().any(|scc| scc.len() > 1)
69	    }
70	
71	    /// 对依赖图进行拓扑排序
72	    ///
73	    /// # 返回值
74	    ///
75	    /// - `Ok(nodes)` — 拓扑排序成功，返回按拓扑序排列的节点列表
76	    /// - `Err(cycle_nodes)` — 图中存在循环依赖，返回参与循环的节点列表
77	    ///
78	    /// 注意：拓扑排序按依赖方向排列，被依赖的节点排在前面。
79	    pub fn topological_order(
80	        graph: &DependencyGraph,
81	    ) -> Result<Vec<DepNode>, Vec<DepNode>> {
82	        let inner = graph.inner_graph();
83	
84	        match toposort(inner, None) {
85	            Ok(order) => {
86	                let nodes: Vec<DepNode> = order
87	                    .into_iter()
88	                    .map(|idx| inner[idx].clone())
89	                    .collect();
90	                Ok(nodes)
91	            }
92	            Err(cycle_error) => {
93	                // cycle_error 中包含参与循环的节点索引
94	                let cycle_node_idx = cycle_error.node_id();
95	                // 收集所有参与循环的节点
96	                let sccs = kosaraju_scc(inner);
97	                let cycle_nodes: Vec<DepNode> = sccs
98	                    .into_iter()
99	                    .filter(|scc| scc.len() > 1)
100	                    .flatten()
101	                    .map(|idx| inner[idx].clone())
102	                    .collect();
103	
104	                // 如果通过 SCC 没找到多节点分量（理论上不应发生），
105	                // 则返回导致拓扑排序失败的节点
106	                if cycle_nodes.is_empty() {
107	                    return Err(vec![inner[cycle_node_idx].clone()]);
108	                }
109	                Err(cycle_nodes)
110	            }
111	        }
112	    }
113	}
