1	//! 三级依赖图
2	//!
3	//! 构建文件级、符号级、模块级三级依赖关系图，
4	//! 支持逐级展开和聚合分析。
5	//!
6	//! # 依赖图级别
7	//!
8	//! - **文件级** — 节点=文件路径，边=import 关系，从 sled 的 `imports:` 命名空间扫描
9	//! - **符号级** — 节点=symbol stable_id，边=调用/引用关系，从 sled 的 `edges:` 和 `refs:` 命名空间扫描
10	//! - **模块级** — 节点=模块/包名，边=跨模块引用，从文件级图聚合/从符号级图按 parent 聚合生成
11	//!
12	//! # 示例
13	//!
14	//! ```ignore
15	//! use codeconnect_index::sled_store::SledStore;
16	//! use codeconnect_graph::dep_graph::DependencyGraph;
17	//!
18	//! let graph = DependencyGraph::build_file_graph(&sled_store)?;
19	//! let deps = graph.get_dependencies("src/main.rs");
20	//! let dependents = graph.get_dependents("src/lib.rs");
21	//! ```
22	
23	use std::collections::HashMap;
24	
25	use petgraph::graph::{DiGraph, NodeIndex};
26	
27	use codeconnect_core::error::CodeConnectError;
28	use codeconnect_core::types::Import;
29	
30	/// 依赖图中节点的类型
31	#[derive(Debug, Clone, PartialEq, Eq)]
32	pub enum DepNodeKind {
33	    /// 文件节点
34	    File,
35	    /// 符号节点
36	    Symbol,
37	    /// 模块节点
38	    Module,
39	}
40	
41	/// 依赖图中的节点
42	///
43	/// `id` 根据 `kind` 的不同有不同的含义：
44	/// - File → 相对于项目根目录的文件路径
45	/// - Symbol → 符号的 stable_id
46	/// - Module → 模块/包的限定名
47	#[derive(Debug, Clone)]
48	pub struct DepNode {
49	    /// 节点的唯一标识（文件路径/模块名/symbol_id）
50	    pub id: String,
51	    /// 节点显示名称
52	    pub name: String,
53	    /// 节点类型
54	    pub kind: DepNodeKind,
55	}
56	
57	/// 依赖图中的边
58	#[derive(Debug, Clone)]
59	pub struct DepEdge {
60	    /// 边的类型（import/call/reference）
61	    pub edge_type: String,
62	    /// 该类型边的数量（聚合计数）
63	    pub count: u64,
64	}
65	
66	/// 三级依赖关系图
67	///
68	/// 基于 petgraph 的有向图，节点是 [`DepNode`]，边是 [`DepEdge`]。
69	/// 内部维护一个 `node_map` 用于通过字符串 ID 快速定位节点索引。
70	pub struct DependencyGraph {
71	    /// petgraph 有向图
72	    pub(crate) graph: DiGraph<DepNode, DepEdge>,
73	    /// 节点 ID → 节点索引 的映射，用于 O(1) 查找
74	    pub(crate) node_map: HashMap<String, NodeIndex>,
75	}
76	
77	impl DependencyGraph {
78	    // ========================================================================
79	    // 构造方法
80	    // ========================================================================
81	
82	    /// 创建空的依赖图
83	    pub fn new() -> Self {
84	        Self {
85	            graph: DiGraph::new(),
86	            node_map: HashMap::new(),
87	        }
88	    }
89	
90	    /// 从 sled 的 imports 命名空间构建文件级依赖图
91	    ///
92	    /// 扫描所有以 `imports:` 为前缀的键，解析导入关系，
93	    /// 构建文件→被导入文件/模块的边。
94	    ///
95	    /// 键格式：`imports:{file_path}::{import_path}`
96	    /// 值格式：`Import` 的 JSON 序列化字节
97	    pub fn build_file_graph(
98	        sled: &codeconnect_index::sled_store::SledStore,
99	    ) -> Result<Self, CodeConnectError> {
100	        let mut graph = Self::new();
101	
102	        // 扫描 imports 命名空间下所有键
103	        let imports = sled.scan_prefix(b"imports:");
104	        for item in imports {
105	            let (key_bytes, value_bytes) = item?;
106	            let key = String::from_utf8_lossy(&key_bytes).to_string();
107	
108	            // 解析键：格式为 "imports:{file_path}::{import_path}"
109	            let key_without_prefix = match key.strip_prefix("imports:") {
110	                Some(rest) => rest,
111	                None => continue,
112	            };
113	
114	            let parts: Vec<&str> = key_without_prefix.splitn(2, "::").collect();
115	            if parts.len() != 2 {
116	                continue;
117	            }
118	
119	            let source_file = parts[0].to_string();
120	            let _import_path = parts[1].to_string();
121	
122	            // 反序列化导入信息
123	            let import: Import = match serde_json::from_slice(&value_bytes) {
124	                Ok(import) => import,
125	                Err(_) => continue,
126	            };
127	
128	            // 解析目标：根据 ImportResolution 确定目标文件或模块
129	            let target = Self::resolve_import_target(&import);
130	            if target.is_empty() {
131	                continue;
132	            }
133	
134	            // 添加节点和边
135	            let source_idx = graph.get_or_create_node(
136	                &source_file,
137	                &source_file,
138	                DepNodeKind::File,
139	            );
140	            let target_idx = graph.get_or_create_node(
141	                &target,
142	                &target,
143	                DepNodeKind::File,
144	            );
145	
146	            // 检查是否已存在相同类型的边，如果存在则计数+1
147	            if let Some(existing_edge) = graph.graph.find_edge(source_idx, target_idx) {
148	                if let Some(edge) = graph.graph.edge_weight_mut(existing_edge) {
149	                    edge.count += 1;
150	                }
151	            } else {
152	                graph.graph.add_edge(
153	                    source_idx,
154	                    target_idx,
155	                    DepEdge {
156	                        edge_type: "import".to_string(),
157	                        count: 1,
158	                    },
159	                );
160	            }
161	        }
162	
163	        Ok(graph)
164	    }
165	
166	    /// 从 sled 的 edges 和 refs 命名空间构建符号级依赖图
167	    ///
168	    /// 扫描调用边和引用边，构建符号之间的依赖关系。
169	    pub fn build_symbol_graph(
170	        sled: &codeconnect_index::sled_store::SledStore,
171	    ) -> Result<Self, CodeConnectError> {
172	        let mut graph = Self::new();
173	
174	        // 扫描调用边：键格式 "edges:{caller_id}::{callee_id}"
175	        let call_edges = sled.scan_prefix(b"edges:");
176	        for item in call_edges {
177	            let (key_bytes, _value_bytes) = item?;
178	            let key = String::from_utf8_lossy(&key_bytes).to_string();
179	
180	            let key_without_prefix = match key.strip_prefix("edges:") {
181	                Some(rest) => rest,
182	                None => continue,
183	            };
184	
185	            let parts: Vec<&str> = key_without_prefix.splitn(2, "::").collect();
186	            if parts.len() != 2 {
187	                continue;
188	            }
189	
190	            let caller_id = parts[0].to_string();
191	            let callee_id = parts[1].to_string();
192	
193	            let caller_idx = graph.get_or_create_node(
194	                &caller_id,
195	                &caller_id,
196	                DepNodeKind::Symbol,
197	            );
198	            let callee_idx = graph.get_or_create_node(
199	                &callee_id,
200	                &callee_id,
201	                DepNodeKind::Symbol,
202	            );
203	
204	            if let Some(existing_edge) = graph.graph.find_edge(caller_idx, callee_idx) {
205	                if let Some(edge) = graph.graph.edge_weight_mut(existing_edge) {
206	                    edge.count += 1;
207	                }
208	            } else {
209	                graph.graph.add_edge(
210	                    caller_idx,
211	                    callee_idx,
212	                    DepEdge {
213	                        edge_type: "call".to_string(),
214	                        count: 1,
215	                    },
216	                );
217	            }
218	        }
219	
220	        // 扫描引用边：键格式 "refs:{ref_id}::{target_id}"
221	        let ref_edges = sled.scan_prefix(b"refs:");
222	        for item in ref_edges {
223	            let (key_bytes, _value_bytes) = item?;
224	            let key = String::from_utf8_lossy(&key_bytes).to_string();
225	
226	            let key_without_prefix = match key.strip_prefix("refs:") {
227	                Some(rest) => rest,
228	                None => continue,
229	            };
230	
231	            let parts: Vec<&str> = key_without_prefix.splitn(2, "::").collect();
232	            if parts.len() != 2 {
233	                continue;
234	            }
235	
236	            let ref_id = parts[0].to_string();
237	            let target_id = parts[1].to_string();
238	
239	            let ref_idx = graph.get_or_create_node(
240	                &ref_id,
241	                &ref_id,
242	                DepNodeKind::Symbol,
243	            );
244	            let target_idx = graph.get_or_create_node(
245	                &target_id,
246	                &target_id,
247	                DepNodeKind::Symbol,
248	            );
249	
250	            if let Some(existing_edge) = graph.graph.find_edge(ref_idx, target_idx) {
251	                if let Some(edge) = graph.graph.edge_weight_mut(existing_edge) {
252	                    edge.count += 1;
253	                }
254	            } else {
255	                graph.graph.add_edge(
256	                    ref_idx,
257	                    target_idx,
258	                    DepEdge {
259	                        edge_type: "reference".to_string(),
260	                        count: 1,
261	                    },
262	                );
263	            }
264	        }
265	
266	        Ok(graph)
267	    }
268	
269	    // ========================================================================
270	    // 查询方法
271	    // ========================================================================
272	
273	    /// 获取某个节点的直接依赖（出边指向的节点列表）
274	    ///
275	    /// 即当前节点依赖于哪些其他节点。
276	    pub fn get_dependencies(&self, node_id: &str) -> Vec<DepNode> {
277	        let node_idx = match self.node_map.get(node_id) {
278	            Some(&idx) => idx,
279	            None => return Vec::new(),
280	        };
281	
282	        self.graph
283	            .neighbors_directed(node_idx, petgraph::Direction::Outgoing)
284	            .map(|idx| self.graph[idx].clone())
285	            .collect()
286	    }
287	
288	    /// 获取某个节点的直接被依赖者（入边来源的节点列表）
289	    ///
290	    /// 即哪些其他节点依赖于当前节点。
291	    pub fn get_dependents(&self, node_id: &str) -> Vec<DepNode> {
292	        let node_idx = match self.node_map.get(node_id) {
293	            Some(&idx) => idx,
294	            None => return Vec::new(),
295	        };
296	
297	        self.graph
298	            .neighbors_directed(node_idx, petgraph::Direction::Incoming)
299	            .map(|idx| self.graph[idx].clone())
300	            .collect()
301	    }
302	
303	    /// 获取所有节点
304	    pub fn nodes(&self) -> Vec<DepNode> {
305	        self.graph.raw_nodes().iter().map(|n| n.weight.clone()).collect()
306	    }
307	
308	    /// 获取所有边
309	    pub fn edges(&self) -> Vec<(DepNode, DepNode, DepEdge)> {
310	        self.graph
311	            .edge_indices()
312	            .filter_map(|edge_idx| {
313	                let (source, target) = self.graph.edge_endpoints(edge_idx)?;
314	                let edge = self.graph[edge_idx].clone();
315	                Some((
316	                    self.graph[source].clone(),
317	                    self.graph[target].clone(),
318	                    edge,
319	                ))
320	            })
321	            .collect()
322	    }
323	
324	    /// 节点数量
325	    pub fn node_count(&self) -> usize {
326	        self.graph.node_count()
327	    }
328	
329	    /// 边数量
330	    pub fn edge_count(&self) -> usize {
331	        self.graph.edge_count()
332	    }
333	
334	    /// 获取底层 petgraph 图的引用（供 cycle_detect 等模块使用）
335	    pub fn inner_graph(&self) -> &DiGraph<DepNode, DepEdge> {
336	        &self.graph
337	    }
338	
339	    // ========================================================================
340	    // 增删改方法
341	    // ========================================================================
342	
343	    /// 添加节点
344	    ///
345	    /// 返回节点索引。如果同 ID 的节点已存在，则返回已有索引而不重复添加。
346	    pub fn add_node(&mut self, node: DepNode) -> NodeIndex {
347	        if let Some(&idx) = self.node_map.get(&node.id) {
348	            return idx;
349	        }
350	        let idx = self.graph.add_node(node.clone());
351	        self.node_map.insert(node.id.clone(), idx);
352	        idx
353	    }
354	
355	    /// 添加边
356	    ///
357	    /// 如果 source 或 target 节点不存在，返回 `None`。
358	    /// 如果同方向边已存在，则计数 +1。
359	    pub fn add_edge(
360	        &mut self,
361	        source_id: &str,
362	        target_id: &str,
363	        edge: DepEdge,
364	    ) -> Option<()> {
365	        let source_idx = *self.node_map.get(source_id)?;
366	        let target_idx = *self.node_map.get(target_id)?;
367	
368	        if let Some(existing) = self.graph.find_edge(source_idx, target_idx) {
369	            if let Some(existing_edge) = self.graph.edge_weight_mut(existing) {
370	                existing_edge.count += 1;
371	            }
372	        } else {
373	            self.graph.add_edge(source_idx, target_idx, edge);
374	        }
375	        Some(())
376	    }
377	
378	    // ========================================================================
379	    // 内部辅助方法
380	    // ========================================================================
381	
382	    /// 根据导入信息解析目标文件或模块名
383	    ///
384	    /// - `Resolved(path)` → 返回解析后的路径
385	    /// - `External(pkg)` → 返回包名作为模块标识
386	    /// - `Unresolved` → 返回空字符串表示无法解析
387	    fn resolve_import_target(import: &Import) -> String {
388	        use codeconnect_core::types::ImportResolution;
389	        match &import.resolution {
390	            ImportResolution::Resolved(path) => path.clone(),
391	            ImportResolution::External(pkg) => pkg.clone(),
392	            ImportResolution::Unresolved => String::new(),
393	        }
394	    }
395	
396	    /// 获取或创建节点
397	    ///
398	    /// 如果节点已存在则返回已有索引，否则创建新节点。
399	    fn get_or_create_node(&mut self, id: &str, name: &str, kind: DepNodeKind) -> NodeIndex {
400	        if let Some(&idx) = self.node_map.get(id) {
401	            return idx;
402	        }
403	
404	        let idx = self.graph.add_node(DepNode {
405	            id: id.to_string(),
406	            name: name.to_string(),
407	            kind,
408	        });
409	        self.node_map.insert(id.to_string(), idx);
410	        idx
411	    }
412	}
