1	//! 类型继承树
2	//!
3	//! 构建类型之间的继承/实现关系图，
4	//! 支持 CHA（Class Hierarchy Analysis）虚拟调用解析。
5	//!
6	//! ## 核心功能
7	//! - 从 sled 存储符号构建类型层次图
8	//! - 查询祖先链（到继承树根的路径）
9	//! - 查询所有后代类型
10	//! - 查询接口的所有实现者
11	//! - 完全独立于存储的纯图算法（通过单元测试验证）
12	
13	use std::collections::{HashMap, VecDeque};
14	
15	use petgraph::graph::DiGraph;
16	use petgraph::visit::EdgeRef;
17	use petgraph::Direction;
18	
19	use codeconnect_core::error::CodeConnectError;
20	use codeconnect_core::types::{Symbol, SymbolKind};
21	use codeconnect_index::sled_store::SledStore;
22	
23	/// 类型层次图中的节点
24	///
25	/// 表示一个可参与继承关系的类型（类、接口、特质、枚举等）。
26	#[derive(Debug, Clone)]
27	pub struct TypeNode {
28	    /// 符号唯一 ID
29	    pub symbol_id: String,
30	    /// 类型名称
31	    pub name: String,
32	    /// 类型种类：class / interface / trait / enum
33	    pub kind: String,
34	    /// 所在源文件路径
35	    pub file_path: String,
36	}
37	
38	/// 继承边
39	///
40	/// 连接父类型和子类型，记录继承关系类型和置信度。
41	#[derive(Debug, Clone)]
42	pub struct InheritEdge {
43	    /// 关系类型："extends"（继承类）或 "implements"（实现接口）
44	    pub relation: String,
45	    /// 置信度 0.0-1.0，基于关系推导方式
46	    pub confidence: f64,
47	}
48	
49	/// 类型继承层次图
50	///
51	/// 基于 petgraph 有向图构建，边方向为：子类型 → 父类型（基类/接口）。
52	/// 即箭头指向"被继承者"。
53	pub struct TypeHierarchy {
54	    /// petgraph 有向图：TypeNode 为节点，InheritEdge 为边
55	    graph: DiGraph<TypeNode, InheritEdge>,
56	    /// 符号名到图节点索引的映射（用于快速查找）
57	    name_to_id: HashMap<String, petgraph::graph::NodeIndex>,
58	}
59	
60	impl TypeHierarchy {
61	    // ========================================================================
62	    // 构造器
63	    // ========================================================================
64	
65	    /// 创建空的类型层次图
66	    pub fn new() -> Self {
67	        Self {
68	            graph: DiGraph::new(),
69	            name_to_id: HashMap::new(),
70	        }
71	    }
72	
73	    /// 从 sled 存储构建类型层次图
74	    ///
75	    /// 遍历 symbol 命名空间中的所有符号，提取 Class/Interface/Trait/Enum
76	    /// 类型，根据 `parent_id` 和符号自身的 `kind` 推断继承关系。
77	    ///
78	    /// ## 继承推断规则
79	    /// - `parent_id` 存在且父符号为 Class/Struct/Enum → "extends" 关系
80	    /// - `parent_id` 存在且父符号为 Interface/Trait → "implements" 关系
81	    /// - 无 `parent_id` 的 Class/Interface/Trait → 继承树根节点
82	    pub fn build_from_sled(sled: &SledStore) -> Result<Self, CodeConnectError> {
83	        let mut hierarchy = Self::new();
84	        let mut all_symbols: HashMap<String, Symbol> = HashMap::new();
85	
86	        // --- 第一步：扫描所有符号 ---
87	        let prefix = b"symbols:";
88	        for item in sled.scan_prefix(prefix) {
89	            let (_key, value) =
90	                item.map_err(|e| CodeConnectError::Index(format!("扫描符号失败: {}", e)))?;
91	
92	            let symbol: Symbol = serde_json::from_slice(&value)
93	                .map_err(|e| CodeConnectError::Index(format!("反序列化符号失败: {}", e)))?;
94	
95	            all_symbols.insert(symbol.id.clone(), symbol);
96	        }
97	
98	        // --- 第二步：添加所有属于类型层次范畴的符号节点 ---
99	        let type_kinds: &[SymbolKind] = &[
100	            SymbolKind::Class,
101	            SymbolKind::Interface,
102	            SymbolKind::Struct,
103	            SymbolKind::Enum,
104	            SymbolKind::Trait,
105	        ];
106	
107	        for symbol in all_symbols.values() {
108	            if type_kinds.contains(&symbol.kind) {
109	                hierarchy.add_node(TypeNode {
110	                    symbol_id: symbol.id.clone(),
111	                    name: symbol.name.clone(),
112	                    kind: kind_to_string(&symbol.kind),
113	                    file_path: symbol.location.file_path.clone(),
114	                });
115	            }
116	        }
117	
118	        // --- 第三步：建立继承边 ---
119	        for symbol in all_symbols.values() {
120	            if let Some(ref parent_id) = symbol.parent_id {
121	                // 当前符号必须是类型层次中的一员
122	                if type_kinds.contains(&symbol.kind) {
123	                    // 父符号可以不直接在当前层次中（可能尚未索引），也要尝试添加
124	                    if let Some(parent_symbol) = all_symbols.get(parent_id) {
125	                        // 确保父节点已存在，若不存在则添加
126	                        if !hierarchy.name_to_id.contains_key(&parent_symbol.name) {
127	                            hierarchy.add_node(TypeNode {
128	                                symbol_id: parent_symbol.id.clone(),
129	                                name: parent_symbol.name.clone(),
130	                                kind: kind_to_string(&parent_symbol.kind),
131	                                file_path: parent_symbol.location.file_path.clone(),
132	                            });
133	                        }
134	
135	                        let (relation, confidence) =
136	                            infer_inherit_relation(&symbol.kind, &parent_symbol.kind);
137	
138	                        hierarchy.add_edge(
139	                            &symbol.name,
140	                            &parent_symbol.name,
141	                            InheritEdge {
142	                                relation,
143	                                confidence,
144	                            },
145	                        );
146	                    }
147	                }
148	            }
149	        }
150	
151	        Ok(hierarchy)
152	    }
153	
154	    /// 向图中添加类型节点
155	    pub fn add_node(&mut self, node: TypeNode) -> petgraph::graph::NodeIndex {
156	        let name = node.name.clone();
157	        let idx = self.graph.add_node(node);
158	        self.name_to_id.insert(name, idx);
159	        idx
160	    }
161	
162	    /// 向图中添加继承边（子类型 → 父类型）
163	    pub fn add_edge(
164	        &mut self,
165	        child_name: &str,
166	        parent_name: &str,
167	        edge: InheritEdge,
168	    ) -> Option<petgraph::graph::EdgeIndex> {
169	        let child = self.name_to_id.get(child_name)?;
170	        let parent = self.name_to_id.get(parent_name)?;
171	        Some(self.graph.add_edge(*child, *parent, edge))
172	    }
173	
174	    // ========================================================================
175	    // 查询方法
176	    // ========================================================================
177	
178	    /// 获取祖先链（从当前类型到继承树根的路径）
179	    ///
180	    /// 使用 BFS 从当前节点向上遍历，返回所有直接和间接父类型。
181	    /// 结果按距离排序，直接父类型在前。
182	    pub fn get_ancestors(&self, symbol_name: &str) -> Vec<TypeNode> {
183	        let start = match self.name_to_id.get(symbol_name) {
184	            Some(idx) => *idx,
185	            None => return Vec::new(),
186	        };
187	
188	        let mut result = Vec::new();
189	        let mut visited = std::collections::HashSet::new();
190	        let mut queue = VecDeque::new();
191	        queue.push_back(start);
192	        visited.insert(start);
193	
194	        while let Some(current) = queue.pop_front() {
195	            // 向上遍历（Direction::Outgoing → 边指向的方向 = 父类型）
196	            for edge in self.graph.edges_directed(current, Direction::Outgoing) {
197	                let parent = edge.target();
198	                if visited.insert(parent) {
199	                    let node = &self.graph[parent];
200	                    result.push(node.clone());
201	                    queue.push_back(parent);
202	                }
203	            }
204	        }
205	
206	        result
207	    }
208	
209	    /// 获取所有后代类型
210	    ///
211	    /// 使用 BFS 从当前节点向下遍历（反向边），返回所有直接和间接子类型。
212	    /// 结果按深度排序，直接子类型在前。
213	    pub fn get_descendants(&self, symbol_name: &str) -> Vec<TypeNode> {
214	        let start = match self.name_to_id.get(symbol_name) {
215	            Some(idx) => *idx,
216	            None => return Vec::new(),
217	        };
218	
219	        let mut result = Vec::new();
220	        let mut visited = std::collections::HashSet::new();
221	        let mut queue = VecDeque::new();
222	        queue.push_back(start);
223	        visited.insert(start);
224	
225	        while let Some(current) = queue.pop_front() {
226	            // 向下遍历（Direction::Incoming → 反向边 = 子类型）
227	            for edge in self.graph.edges_directed(current, Direction::Incoming) {
228	                let child = edge.source();
229	                if visited.insert(child) {
230	                    let node = &self.graph[child];
231	                    result.push(node.clone());
232	                    queue.push_back(child);
233	                }
234	            }
235	        }
236	
237	        result
238	    }
239	
240	    /// 获取接口的所有实现者
241	    ///
242	    /// 仅返回通过 "implements" 边连接的后代类型。
243	    /// 适用于 Interface/Trait 节点。
244	    pub fn get_implementations(&self, interface_name: &str) -> Vec<TypeNode> {
245	        let start = match self.name_to_id.get(interface_name) {
246	            Some(idx) => *idx,
247	            None => return Vec::new(),
248	        };
249	
250	        let mut result = Vec::new();
251	        let mut visited = std::collections::HashSet::new();
252	        let mut queue = VecDeque::new();
253	        queue.push_back(start);
254	        visited.insert(start);
255	
256	        while let Some(current) = queue.pop_front() {
257	            for edge in self.graph.edges_directed(current, Direction::Incoming) {
258	                // 只收集 "implements" 边
259	                if edge.weight().relation != "implements" {
260	                    continue;
261	                }
262	                let child = edge.source();
263	                if visited.insert(child) {
264	                    let node = &self.graph[child];
265	                    result.push(node.clone());
266	                    // 继续向下查找传递实现
267	                    queue.push_back(child);
268	                }
269	            }
270	        }
271	
272	        result
273	    }
274	
275	    /// 获取图中节点总数
276	    pub fn node_count(&self) -> usize {
277	        self.graph.node_count()
278	    }
279	
280	    /// 获取图中边总数
281	    pub fn edge_count(&self) -> usize {
282	        self.graph.edge_count()
283	    }
284	
285	    /// 获取图中所有类型节点（快照）
286	    pub fn all_nodes(&self) -> Vec<TypeNode> {
287	        self.graph.raw_nodes().iter().map(|n| n.weight.clone()).collect()
288	    }
289	
290	    /// 根据名称查找类型节点
291	    pub fn find_node(&self, name: &str) -> Option<TypeNode> {
292	        self.name_to_id.get(name).map(|&idx| self.graph[idx].clone())
293	    }
294	}
