310	/// 将 SymbolKind 转换为字符串描述
311	fn kind_to_string(kind: &SymbolKind) -> String {
312	    match kind {
313	        SymbolKind::Class => "class".to_string(),
314	        SymbolKind::Interface => "interface".to_string(),
315	        SymbolKind::Struct => "struct".to_string(),
316	        SymbolKind::Enum => "enum".to_string(),
317	        SymbolKind::Trait => "trait".to_string(),
318	        SymbolKind::Function => "function".to_string(),
319	        SymbolKind::Method => "method".to_string(),
320	        SymbolKind::TypeAlias => "type_alias".to_string(),
321	        SymbolKind::Variable => "variable".to_string(),
322	        SymbolKind::Field => "field".to_string(),
323	        SymbolKind::Parameter => "parameter".to_string(),
324	        SymbolKind::Module => "module".to_string(),
325	        SymbolKind::Macro => "macro".to_string(),
326	        SymbolKind::Unknown(s) => format!("unknown({})", s),
327	    }
328	}
329	
330	/// 根据子类型和父类型的 SymbolKind 推断继承关系
331	///
332	/// ## 规则
333	/// - 子类型为 Class/Struct → 父类型为 Class/Struct/Enum → "extends"
334	/// - 子类型为 Class/Struct → 父类型为 Interface/Trait → "implements"
335	/// - 子类型为 Interface/Trait → 父类型为 Interface/Trait → "extends"
336	/// - 其他情况 → "unknown"（低置信度）
337	fn infer_inherit_relation(child_kind: &SymbolKind, parent_kind: &SymbolKind) -> (String, f64) {
338	    use SymbolKind::*;
339	
340	    // 判断是否为"类"类型（可以有实例）
341	    let is_class_like = |k: &SymbolKind| matches!(k, Class | Struct | Enum);
342	    // 判断是否为"接口"类型
343	    let is_interface_like = |k: &SymbolKind| matches!(k, Interface | Trait);
344	
345	    match (child_kind, parent_kind) {
346	        // 类继承类
347	        (child, parent) if is_class_like(child) && is_class_like(parent) => {
348	            ("extends".to_string(), 0.9)
349	        }
350	        // 类实现接口
351	        (child, parent) if is_class_like(child) && is_interface_like(parent) => {
352	            ("implements".to_string(), 0.9)
353	        }
354	        // 接口继承接口
355	        (child, parent) if is_interface_like(child) && is_interface_like(parent) => {
356	            ("extends".to_string(), 0.8)
357	        }
358	        // 未知关系
359	        _ => ("extends".to_string(), 0.3),
360	    }
361	}
