1	//! 代码质量指标
2	//!
3	//! 提供单一符号和批量代码质量指标计算：
4	//! - **圈复杂度** — 基于 AST 分支节点计数的控制流复杂度
5	//! - **出入度** — 基于调用图的 fan-in / fan-out 统计
6	//! - **继承深度** — 基于类型层次图的继承链深度
7	//! - **死代码检测** — 基于调用图可达性分析
8	
9	use std::collections::{HashSet, VecDeque};
10	
11	use codeconnect_core::types::Symbol;
12	
13	use crate::call_graph::CallGraph;
14	use crate::type_hierarchy::TypeHierarchy;
15	
16	/// 代码质量指标
17	///
18	/// 汇总单个符号的复杂度、耦合度、继承深度等指标。
19	#[derive(Debug, Clone)]
20	pub struct CodeMetrics {
21	    /// 符号唯一 ID
22	    pub symbol_id: String,
23	    /// 符号名称
24	    pub name: String,
25	    /// 圈复杂度（基于分支节点统计）
26	    pub cyclomatic_complexity: u64,
27	    /// 入度（被其他符号调用的次数）
28	    pub fan_in: u64,
29	    /// 出度（调用其他符号的次数）
30	    pub fan_out: u64,
31	    /// 继承深度（从当前类型到继承树根的距离）
32	    pub depth_of_inheritance: u64,
33	}
34	
35	/// 死代码条目
36	///
37	/// 表示一个从入口点不可达的、可能为死代码的符号。
38	#[derive(Debug, Clone)]
39	pub struct DeadCodeEntry {
40	    /// 符号唯一 ID
41	    pub symbol_id: String,
42	    /// 符号名称
43	    pub name: String,
44	    /// 置信度 0.0-1.0，值越低越可能是死代码
45	    /// 1.0 = 完全不可达（肯定是死代码）
46	    /// 0.5 = 可能存在间接引用但未检测到
47	    pub confidence: f64,
48	    /// 标记为死代码的原因描述
49	    pub reason: String,
50	}
51	
52	/// 指标计算器
53	///
54	/// 提供批量计算和死代码检测功能。
55	/// 自身不维护状态，所有方法均为纯函数。
56	pub struct MetricCalculator;
57	
58	impl MetricCalculator {
59	    // ========================================================================
60	    // 圈复杂度
61	    // ========================================================================
62	
63	    /// 计算单个符号的圈复杂度
64	    ///
65	    /// ## 算法
66	    /// 1. 如果 `symbol.complexity` 已有值，直接返回（来自解析器的预计算结果）
67	    /// 2. 否则对 `source` 文本进行轻量级分析，统计分支关键字：
68	    ///    - 条件分支: `if`, `else if`
69	    ///    - 循环: `for`, `while`, `loop`
70	    ///    - 模式匹配: `match`, `case`, `switch`
71	    ///    - 异常处理: `catch`, `except`, `rescue`
72	    ///    - 逻辑运算符（短路求值）: `&&`, `||`
73	    ///    - 空值合并: `?.`, `??`
74	    ///    - 三元运算符: `?`
75	    /// 3. 圈复杂度 = 1（函数入口） + 分支节点总数
76	    pub fn compute_complexity(symbol: &Symbol, source: &str) -> u64 {
77	        // 优先使用解析器预计算的值
78	        if let Some(complexity) = symbol.complexity {
79	            return complexity;
80	        }
81	
82	        // 对源文本做词法级别的分支关键字计数
83	        let mut complexity: u64 = 1; // 函数入口基准值
84	
85	        // 使用简单的空格分隔进行词法分析（非完整解析，但足够准确）
86	        let tokens: Vec<&str> = source
87	            .split(|c: char| c.is_whitespace() || c == '(' || c == ')' || c == '{' || c == '}' || c == ';' || c == ',')
88	            .filter(|s| !s.is_empty())
89	            .collect();
90	
91	        for &token in &tokens {
92	            match token {
93	                // 条件分支
94	                "if" | "elif" | "elsif" | "elseif" => complexity += 1,
95	                // 循环
96	                "for" | "while" | "loop" => complexity += 1,
97	                // 模式匹配
98	                "match" | "case" | "switch" => complexity += 1,
99	                // 异常处理
100	                "catch" | "except" | "rescue" | "finally" => complexity += 1,
101	                // 逻辑运算符（短路求值产生分支）
102	                "&&" | "||" => complexity += 1,
103	                _ => {}
104	            }
105	        }
106	
107	        // 统计三元运算符 `?`（在 token 中单独出现）
108	        complexity += tokens.iter().filter(|&&t| t == "?").count() as u64;
109	
110	        // 统计空值合并运算符 `??` 和可选链 `?.`
111	        // 这需要在原始源文本上统计
112	        complexity += source.matches("??").count() as u64;
113	        complexity += source.matches("?.").count() as u64;
114	
115	        complexity
116	    }
117	
118	    // ========================================================================
119	    // 批量指标计算
120	    // ========================================================================
121	
122	    /// 批量计算所有符号的代码质量指标
123	    ///
124	    /// ## 计算内容
125	    /// - **圈复杂度** — 从 `symbol.complexity` 字段获取（解析器预计算）
126	    /// - **fan_in** — 调用图中指向当前符号的入边数量
127	    /// - **fan_out** — 调用图中从当前符号出发的出边数量
128	    /// - **继承深度** — 类型层次图中当前符号到根的距离
129	    pub fn compute_all(
130	        symbols: &[Symbol],
131	        call_graph: &CallGraph,
132	        type_hierarchy: &TypeHierarchy,
133	    ) -> Vec<CodeMetrics> {
134	        symbols
135	            .iter()
136	            .map(|symbol| {
137	                // 圈复杂度：优先用预计算值，否则默认为 1
138	                let cyclomatic_complexity = symbol.complexity.unwrap_or(1);
139	
140	                // 出入度：从调用图获取
141	                let (fan_in, fan_out) = call_graph.degree(&symbol.name);
142	
143	                // 继承深度：从类型层次图计算祖先数量
144	                let ancestors = type_hierarchy.get_ancestors(&symbol.name);
145	                let depth_of_inheritance = ancestors.len() as u64;
146	
147	                CodeMetrics {
148	                    symbol_id: symbol.id.clone(),
149	                    name: symbol.name.clone(),
150	                    cyclomatic_complexity,
151	                    fan_in,
152	                    fan_out,
153	                    depth_of_inheritance,
154	                }
155	            })
