159	    // ========================================================================
160	    // 死代码检测
161	    // ========================================================================
162	
163	    /// 检测死代码
164	    ///
165	    /// ## 算法
166	    /// 从入口点（main 函数、导出的 pub 函数等）出发，在调用图上做正向 BFS
167	    /// 可达性分析。即从每个入口点开始，沿"调用者→被调用者"方向（出边）遍历，
168	    /// 将能到达的节点标记为"可达"。
169	    ///
170	    /// 最后，所有未被标记为可达的符号即为**可能死代码**。
171	    ///
172	    /// ## 置信度计算
173	    /// - 1.0 — 完全不可达（没有任何入边）
174	    /// - 0.8 — 不可达但至少有一条入边（可能是反射/回调等间接调用）
175	    /// - 0.5 — 不可达但名称匹配常见模式（如 `test_*`）
176	    pub fn detect_dead_code(
177	        all_symbols: &[String],
178	        call_graph: &CallGraph,
179	        entry_points: &[String],
180	    ) -> Vec<DeadCodeEntry> {
181	        // 第1步: 构建可达性集合
182	        let mut reachable = HashSet::new();
183	        let mut queue = VecDeque::new();
184	
185	        // 从入口点开始
186	        for entry in entry_points {
187	            reachable.insert(entry.clone());
188	            queue.push_back(entry.clone());
189	        }
190	
191	        // BFS 正向遍历：从入口点沿出边找到被调用的符号
192	        while let Some(current) = queue.pop_front() {
193	            // 获取 current 调用的所有符号（被调用者）
194	            let callees = call_graph.get_callees(&current);
195	            for callee in callees {
196	                if reachable.insert(callee.clone()) {
197	                    queue.push_back(callee);
198	                }
199	            }
200	        }
201	
202	        // 第2步: 找出不可达符号并计算置信度
203	        let mut dead_entries = Vec::new();
204	        for symbol_name in all_symbols {
205	            if reachable.contains(symbol_name.as_str()) {
206	                continue;
207	            }
208	
209	            let (fan_in, _fan_out) = call_graph.degree(symbol_name);
210	
211	            // 确定置信度和原因
212	            // 注意：名称模式匹配优先于 fan_in 检查，
213	            // 这样 test_* 和 _ 前缀符号即使 fan_in=0 也能获得正确的置信度
214	            let (confidence, reason) = if symbol_name.starts_with("test_") || symbol_name.contains("_test") {
215	                // 可能是测试代码
216	                (0.5, "未被入口点可达，但名称匹配测试模式".to_string())
217	            } else if symbol_name.starts_with('_') {
218	                // 可能是内部/私有函数
219	                (0.7, "未被入口点可达，名称前缀暗示内部函数".to_string())
220	            } else if fan_in == 0 {
221	                // 完全孤立
222	                (1.0, "从任何入口点都不可达，且未被任何符号调用".to_string())
223	            } else {
224	                // 有入边但不可达（可能是反射、动态调用等）
225	                (0.8, format!(
226	                    "未被入口点可达，但被 {} 个符号调用（可能是间接/动态调用）",
227	                    fan_in
228	                ))
229	            };
230	
231	            dead_entries.push(DeadCodeEntry {
232	                symbol_id: format!("dead_{}", symbol_name),
233	                name: symbol_name.clone(),
234	                confidence,
235	                reason,
236	            });
237	        }
238	
239	        dead_entries
240	    }
241	}
