    fn build_test_graph() -> CallGraph {
        let mut graph = CallGraph::new();
        graph.add_edge_raw("A", "B");
        graph.add_edge_raw("B", "C");
        graph.add_edge_raw("C", "D");
        graph
    }

    #[test]
    fn test_direct_impact() {
        let graph = build_test_graph();
        let analyzer = ImpactAnalyzer::from_graph(graph, 5);

        // 变更 B → 直接影响者 A（直接调用者）
        let report = analyzer.analyze(&["B".to_string()]);

        assert_eq!(report.direct_impacts.len(), 1);
        assert_eq!(report.direct_impacts[0].name, "A");
        assert_eq!(report.direct_impacts[0].distance, 1);
        assert_eq!(report.transitive_impacts.len(), 0);
    }

    #[test]
    fn test_transitive_impact() {
        let graph = build_test_graph();
        let analyzer = ImpactAnalyzer::from_graph(graph, 5);

        // 变更 D → A,B,C 都是调用者，A 距离3（传递）, B 距离2（传递）, C 距离1（直接）
        let report = analyzer.analyze(&["D".to_string()]);

        // C 是直接调用者
        assert_eq!(report.direct_impacts.len(), 1);
        assert!(report.direct_impacts.iter().any(|e| e.name == "C"));

        // A 和 B 是传递调用者
        assert_eq!(report.transitive_impacts.len(), 2);
        let trans_names: Vec<&str> = report.transitive_impacts.iter().map(|e| e.name.as_str()).collect();
        assert!(trans_names.contains(&"A"));
        assert!(trans_names.contains(&"B"));
    }

    #[test]
    fn test_multiple_changed_symbols() {
        let graph = build_test_graph();
        let analyzer = ImpactAnalyzer::from_graph(graph, 5);

        // 同时变更 B 和 D
        let report = analyzer.analyze(&["B".to_string(), "D".to_string()]);

        // B 的直接调用者：A
        // D 的直接调用者：C
        // D 的传递调用者：A, B
        // A 被 B 和 D 两个变更都触发，但去重后只出现一次
        assert!(report.direct_impacts.iter().any(|e| e.name == "A")); // B 的直接调用者
        assert!(report.direct_impacts.iter().any(|e| e.name == "C")); // D 的直接调用者
        assert_eq!(report.direct_impacts.len(), 2);

        assert!(report.transitive_impacts.iter().any(|e| e.name == "B")); // D 的传递调用者
        // A 已在 direct 中发现，不会在 transitive 中重复
        assert_eq!(report.transitive_impacts.len(), 1);

        // 总共去重后受影响数：A, C, B = 3
        assert_eq!(report.total_affected(), 3);
    }

    #[test]
    fn test_empty_changes() {
        let graph = build_test_graph();
        let analyzer = ImpactAnalyzer::from_graph(graph, 5);

        let report = analyzer.analyze(&[]);
        assert!(report.direct_impacts.is_empty());
        assert!(report.transitive_impacts.is_empty());
        assert_eq!(report.total_affected(), 0);
    }

    #[test]
    fn test_max_depth_limit() {
        let graph = build_test_graph();
        // max_depth = 1，只查找直接调用者
        let analyzer = ImpactAnalyzer::from_graph(graph, 1);

        // 变更 D，但 max_depth=1 只能找到 C（直接调用者）
        let report = analyzer.analyze(&["D".to_string()]);

        assert_eq!(report.direct_impacts.len(), 1);
        assert_eq!(report.direct_impacts[0].name, "C");
        assert_eq!(report.transitive_impacts.len(), 0);
    }
}

//! 语义搜索服务
//!
//! 提供基于 tantivy 全文索引的代码搜索能力：
//! - `search_pattern` — 在代码全文内容中搜索模式
//! - `find_similar` — 按名称模糊匹配查找相似符号

use codeconnect_core::error::CodeConnectError;
use codeconnect_index::query_engine::QueryEngine;
use codeconnect_index::tantivy_index::SymbolSearchResult;

/// 语义搜索服务
///
/// 封装 [`QueryEngine`] 的全文搜索能力，提供模式搜索和相似符号查找。
///
/// # 搜索策略
/// - **search_pattern** — 在符号名中搜索指定模式（模糊匹配）
/// - **find_similar** — 根据名称查找相似符号（利用 tantivy 的分词和 BM25 评分）
pub struct SemanticSearch<'a> {
    /// 底层查询引擎引用
    engine: &'a QueryEngine,
}

impl<'a> SemanticSearch<'a> {
    /// 创建新的语义搜索服务
    ///
    /// # 参数
    /// - `engine` — 已初始化的查询引擎引用
    pub fn new(engine: &'a QueryEngine) -> Self {
        Self { engine }
    }

    // =========================================================================
    // 模式搜索
    // =========================================================================

    /// 在符号名中搜索指定模式
    ///
    /// 使用 tantivy 的 BM25 全文搜索对 `name` 字段进行匹配。
    /// 支持 tantivy 查询语法（如通配符 `*`、模糊匹配 `~`、短语 `"..."`）。
    ///
    /// # 参数
    /// - `pattern` — 搜索模式（支持 tantivy 查询语法）
    /// - `limit` — 最多返回的结果数
    ///
    /// # 返回
    /// 按相关度排序的搜索结果列表。
    ///
    /// # 示例
    /// - `"handle"` — 精确/模糊匹配函数名 handle
    /// - `"handle*"` — 匹配所有以 handle 开头的符号
    /// - `"event_handle"` — 匹配包含 event_handle 的符号
    pub fn search_pattern(
        &self,
        pattern: &str,
        limit: usize,
    ) -> Result<Vec<SymbolSearchResult>, CodeConnectError> {
        self.engine.search_by_name(pattern, None, None, limit)
    }

    // =========================================================================
    // 相似符号查找
    // =========================================================================

    /// 查找与指定名称相似的符号
    ///
    /// 将 `name` 直接作为查询词进行全文搜索，
    /// 利用 tantivy 的分词和 BM25 评分返回相似结果。
    /// 搜索结果中的第一个（评分最高的）通常就是精确匹配，
    /// 后续的结果是名称中包含相似词汇的符号。
    ///
    /// # 参数
    /// - `name` — 用于查找相似符号的名称
    /// - `limit` — 最多返回的结果数
    ///
    /// # 返回
    /// 按相关度排序的相似符号列表。
    ///
    /// # 示例
    /// 搜索 "handle_event" 可能返回：
    /// - handle_event（精确匹配，最高评分）
    /// - handle_click_event（包含 event 和 handle）
    /// - process_event（包含 event）
    pub fn find_similar(
        &self,
        name: &str,
        limit: usize,
    ) -> Result<Vec<SymbolSearchResult>, CodeConnectError> {
        self.engine.search_by_name(name, None, None, limit)
    }

    // =========================================================================
    // 辅助方法
    // =========================================================================

    /// 按完整名称精确搜索
    ///
    /// 精确搜索适合需要完全匹配符号名的场景。
    /// 注意：tantivy 会对查询词分词，所以此方法仍然可能
    /// 匹配含有查询词其他部分的符号。如需严格精确匹配，
    /// 应在上层对结果进行二次过滤。
    ///
    /// # 参数
    /// - `exact_name` — 要精确匹配的符号名
    /// - `limit` — 最多返回的结果数
    pub fn exact_search(
        &self,
        exact_name: &str,
        limit: usize,
    ) -> Result<Vec<SymbolSearchResult>, CodeConnectError> {
        // 使用引号包裹做短语查询，提高精确度
        let query = format!("\"{}\"", exact_name);
        self.engine.search_by_name(&query, None, None, limit)
    }
}

