    /// 构建测试依赖图：A → B → C → D，B → A（形成循环）
    fn build_cyclic_test_graph() -> DependencyGraph {
        let mut graph = DependencyGraph::new();

        graph.add_node(DepNode {
            id: "src/a.rs".into(),
            name: "a.rs".into(),
            kind: DepNodeKind::File,
        });
