            kind: DepNodeKind::File,
        });
        graph.add_node(DepNode {
            id: "src/service.rs".into(),
            name: "service.rs".into(),
            kind: DepNodeKind::File,
        });
        graph.add_node(DepNode {
            id: "src/data.rs".into(),
            name: "data.rs".into(),
            kind: DepNodeKind::File,
        });

        let make_edge = || DepEdge {
            edge_type: "import".into(),
            count: 1,
        };

        // ui → service → data
        graph.add_edge("src/ui.rs", "src/service.rs", make_edge());
        graph.add_edge("src/service.rs", "src/data.rs", make_edge());

        graph
    }

    #[test]
    fn test_detect_cycles_cyclic() {
        let graph = build_cyclic_test_graph();
        let arch = ArchQuery::from_graph(graph);

        assert!(arch.has_cycle());
        let cycles = arch.detect_cycles();
        assert!(!cycles.is_empty());
    }

    #[test]
    fn test_detect_cycles_acyclic() {
        let graph = build_acyclic_test_graph();
        let arch = ArchQuery::from_graph(graph);

        assert!(!arch.has_cycle());
        let cycles = arch.detect_cycles();
        assert!(cycles.is_empty());
    }

    #[test]
    fn test_check_forbidden_dependency_rule() {
        let graph = build_acyclic_test_graph();
        let arch = ArchQuery::from_graph(graph);

        let rules = vec![ArchitectureRule {
            name: "禁止 UI 直接依赖 Data".into(),
            rule_type: RuleType::ForbiddenDependency,
            description: "UI 层不应直接引用数据层".into(),
            source_pattern: "src/ui.rs".into(),
            target_pattern: "src/data.rs".into(),
        }];

        let violations = arch.check_rules(&rules);
        // ui → service → data，ui 不直接依赖 data，所以没有违规
        assert!(violations.is_empty());
    }

    #[test]
    fn test_check_forbidden_dependency_violated() {
        let mut graph = DependencyGraph::new();

        graph.add_node(DepNode {
            id: "src/ui.rs".into(),
            name: "ui.rs".into(),
            kind: DepNodeKind::File,
        });
        graph.add_node(DepNode {
            id: "src/data.rs".into(),
            name: "data.rs".into(),
            kind: DepNodeKind::File,
        });

        let make_edge = || DepEdge {
            edge_type: "import".into(),
            count: 1,
        };

        // 直接依赖：ui → data（违反规则）
        graph.add_edge("src/ui.rs", "src/data.rs", make_edge());

        let arch = ArchQuery::from_graph(graph);

        let rules = vec![ArchitectureRule {
            name: "禁止 UI 直接依赖 Data".into(),
            rule_type: RuleType::ForbiddenDependency,
            description: "UI 层不应直接引用数据层".into(),
            source_pattern: "src/ui.rs".into(),
            target_pattern: "src/data.rs".into(),
        }];

        let violations = arch.check_rules(&rules);
        assert_eq!(violations.len(), 1);
        assert_eq!(violations[0].rule_name, "禁止 UI 直接依赖 Data");
    }

    #[test]
    fn test_glob_match() {
        assert!(ArchQuery::glob_match("src/*.rs", "src/main.rs"));
        assert!(ArchQuery::glob_match("*.rs", "main.rs"));
        assert!(ArchQuery::glob_match("*", "anything"));
        assert!(ArchQuery::glob_match("src/ui.rs", "src/ui.rs"));
        assert!(!ArchQuery::glob_match("src/ui.rs", "src/service.rs"));
        assert!(ArchQuery::glob_match("src/**/*.rs", "src/ui/components/button.rs"));
    }

    #[test]
    fn test_analyze_comprehensive() {
        let graph = build_acyclic_test_graph();
        let arch = ArchQuery::from_graph(graph);

        let rules = vec![ArchitectureRule {
            name: "禁止反向依赖".into(),
            rule_type: RuleType::ForbiddenDependency,
            description: "数据层不应依赖 UI 层".into(),
            source_pattern: "src/data.rs".into(),
            target_pattern: "src/ui.rs".into(),
        }];

        let result = arch.analyze(&rules);

        assert_eq!(result.node_count, 3);
        assert_eq!(result.edge_count, 2);
        assert!(!result.has_cycle);
        assert!(result.cycles.is_empty());
        // data 不依赖 ui，所以无违规
        assert!(result.violations.is_empty());
    }

    #[test]
    fn test_get_dependencies_and_dependents() {
        let graph = build_acyclic_test_graph();
        let arch = ArchQuery::from_graph(graph);

        // ui 依赖 service
        let ui_deps = arch.get_dependencies("src/ui.rs");
        assert_eq!(ui_deps.len(), 1);
        assert_eq!(ui_deps[0].id, "src/service.rs");

        // service 被 ui 依赖
        let service_dependents = arch.get_dependents("src/service.rs");
        assert_eq!(service_dependents.len(), 1);
        assert_eq!(service_dependents[0].id, "src/ui.rs");
    }
}

//! 死代码检测服务
//!
//! 对代码库做可达性分析，从入口点出发遍历调用图，
//! 标记从任何入口点都不可达的符号为候选死代码。

use codeconnect_core::error::CodeConnectError;
use codeconnect_graph::call_graph::CallGraph;
use codeconnect_graph::metrics::{DeadCodeEntry, MetricCalculator};

/// 死代码检测服务
///
/// 封装 [`MetricCalculator::detect_dead_code`]，从 sled 存储或已有调用图构建。
/// 通过 BFS 可达性分析找出从入口点不可达的符号。
///
/// # 算法
/// 从入口点（如 main 函数、导出的 pub 函数）出发，沿调用图的出边
/// 方向做正向 BFS，标记所有可达符号。未被标记的符号即为死代码候选。
pub struct DeadCodeDetector {
    /// 调用图实例
    call_graph: CallGraph,
}

impl DeadCodeDetector {
    /// 从 sled 存储构建死代码检测器
    ///
    /// # 参数
    /// - `sled` — 已打开的 sled 数据库实例
    pub fn new(
        sled: &codeconnect_index::sled_store::SledStore,
    ) -> Result<Self, CodeConnectError> {
        let call_graph = CallGraph::build_from_sled(sled)?;
        Ok(Self { call_graph })
    }

    /// 从已有调用图构建死代码检测器
    ///
    /// # 参数
    /// - `call_graph` — 已构建好的调用图
    pub fn from_graph(call_graph: CallGraph) -> Self {
        Self { call_graph }
    }

    /// 执行死代码检测
    ///
    /// 从指定的入口点列表出发，在调用图上做正向 BFS 可达性分析。
    /// 所有不可达的符号会被标记为死代码，附带置信度和原因描述。
    ///
    /// # 参数
    /// - `all_symbols` — 所有符号的名称列表
    /// - `entry_points` — 入口点符号名称列表（如 `["main", "pub_api"]`）
    ///
    /// # 返回
    /// 死代码条目列表，按置信度降序排列（最可能是死代码的在前）。
    ///
    /// # 置信度
    /// - 1.0 — 完全不可达且无入边（高度确定性）
    /// - 0.8 — 不可达但有入边（可能是反射/动态调用）
    /// - 0.7 — 不可达但名称以 `_` 开头（暗示内部函数）
    /// - 0.5 — 不可达但名称匹配测试模式（`test_*` 或 `*_test`）
    pub fn detect(
        &self,
        all_symbols: &[String],
        entry_points: &[String],
    ) -> Vec<DeadCodeEntry> {
        let mut entries = MetricCalculator::detect_dead_code(
            all_symbols,
            &self.call_graph,
            entry_points,
        );

        // 按置信度降序排列：最可能是死代码的排前面
        entries.sort_by(|a, b| {
            b.confidence
                .partial_cmp(&a.confidence)
                .unwrap_or(std::cmp::Ordering::Equal)
        });

        entries
    }

    /// 获取调用图的节点数
    pub fn node_count(&self) -> usize {
        self.call_graph.node_count()
    }

    /// 获取调用图的边数
    pub fn edge_count(&self) -> usize {
        self.call_graph.edge_count()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// 构建测试调用图
    fn build_test_graph() -> CallGraph {
        let mut graph = CallGraph::new();
        // main → helper → util
        // orphan → dead_func（孤立子图）
        graph.add_edge_raw("main", "helper");
        graph.add_edge_raw("helper", "util");
        graph.add_edge_raw("orphan", "dead_func");
        graph
    }

    #[test]
    fn test_detect_dead_code() {
        let graph = build_test_graph();
        let detector = DeadCodeDetector::from_graph(graph);

        let all_symbols: Vec<String> = vec![
            "main".into(),
            "helper".into(),
            "util".into(),
            "orphan".into(),
            "dead_func".into(),
        ];
        let entry_points: Vec<String> = vec!["main".into()];

        let dead = detector.detect(&all_symbols, &entry_points);

        // orphan 和 dead_func 不可达
        assert_eq!(dead.len(), 2);
        let dead_names: Vec<&str> = dead.iter().map(|d| d.name.as_str()).collect();
        assert!(dead_names.contains(&"orphan"));
        assert!(dead_names.contains(&"dead_func"));
    }

    #[test]
    fn test_no_entry_points() {
        let graph = build_test_graph();
        let detector = DeadCodeDetector::from_graph(graph);

        let all_symbols: Vec<String> = vec!["main".into(), "helper".into()];
        let entry_points: Vec<String> = vec![];

        // 没有入口点 → 所有符号都不可达
        let dead = detector.detect(&all_symbols, &entry_points);
        assert_eq!(dead.len(), 2);
    }

    #[test]
    fn test_all_reachable() {
        let mut graph = CallGraph::new();
        graph.add_edge_raw("main", "helper");
        graph.add_edge_raw("helper", "util");

        let detector = DeadCodeDetector::from_graph(graph);

        let all_symbols: Vec<String> = vec!["main".into(), "helper".into(), "util".into()];
        let entry_points: Vec<String> = vec!["main".into()];

        let dead = detector.detect(&all_symbols, &entry_points);
        assert!(dead.is_empty());
    }

    #[test]
    fn test_sorted_by_confidence_desc() {
        let mut graph = CallGraph::new();
        graph.add_edge_raw("orphan", "dead_func");

        let detector = DeadCodeDetector::from_graph(graph);

        let all_symbols: Vec<String> = vec![
            "main".into(),
            "orphan".into(),
            "dead_func".into(),
            "_internal".into(),
        ];
        let entry_points: Vec<String> = vec!["main".into()];

        let dead = detector.detect(&all_symbols, &entry_points);

        // 验证按置信度降序排列
        for i in 1..dead.len() {
            assert!(
                dead[i - 1].confidence >= dead[i].confidence,
                "结果应按置信度降序排列"
            );
        }
    }
}

//! 代码质量指标服务
//!
//! 封装 [`MetricCalculator`]，提供单个符号的圈复杂度计算和
//! 批量代码质量指标统计。此模块是 graph::metrics 的薄封装。

use codeconnect_core::types::Symbol;
use codeconnect_graph::call_graph::CallGraph;
use codeconnect_graph::metrics::{CodeMetrics, MetricCalculator};
use codeconnect_graph::type_hierarchy::TypeHierarchy;

/// 代码质量指标服务
///
/// 封装 graph::metrics 的指标计算功能，提供面向服务层的统一接口。
pub struct MetricsService;

impl MetricsService {
    /// 计算单个符号的圈复杂度
    ///
    /// 优先使用 symbol.complexity 预计算值（来自解析器）。
    /// 如果预计算值不存在，则对 source 文本做词法级分支关键字统计。
    ///
    /// # 参数
    /// - `symbol` — 目标符号
    /// - `source` — 符号所在文件的源码内容（用于回退计算）
    ///
    /// # 返回
    /// 圈复杂度（基准值为 1，即无分支的函数）。
    pub fn cyclomatic_complexity(symbol: &Symbol, source: &str) -> u64 {
        MetricCalculator::compute_complexity(symbol, source)
    }

    /// 批量计算所有符号的代码质量指标
    ///
    /// 对每个符号计算：
    /// - 圈复杂度（来自预计算值或默认 1）
    /// - fan_in（入度，被调用次数）
    /// - fan_out（出度，调用次数）
    /// - 继承深度（类型层次中的祖先数量）
    ///
    /// # 参数
    /// - `symbols` — 符号列表
    /// - `call_graph` — 调用图（用于计算出入度）
    /// - `type_hierarchy` — 类型层次图（用于计算继承深度）
    ///
    /// # 返回
    /// 每个符号的完整代码质量指标列表。
    pub fn compute_all(
        symbols: &[Symbol],
        call_graph: &CallGraph,
        type_hierarchy: &TypeHierarchy,
    ) -> Vec<CodeMetrics> {
        MetricCalculator::compute_all(symbols, call_graph, type_hierarchy)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use codeconnect_core::types::{SourceLocation, SymbolKind};

    /// 创建测试用 Symbol
    fn make_symbol(name: &str, complexity: Option<u64>) -> Symbol {
        Symbol {
            id: format!("id_{}", name),
            name: name.to_string(),
            kind: SymbolKind::Function,
            location: SourceLocation {
                file_path: "test.rs".to_string(),
                line: 1,
                column: 1,
                end_line: 1,
                end_column: 1,
            },
            signature: None,
            doc_comment: None,
            parent_id: None,
            modifiers: vec![],
            is_exported: false,
            complexity,
        }
    }

    #[test]
    fn test_cyclomatic_complexity_uses_precomputed() {
        let symbol = make_symbol("my_fn", Some(42));
        // 即使 source 很简单，也应使用预计算值
        let complexity = MetricsService::cyclomatic_complexity(&symbol, "fn my_fn() { return 1; }");
        assert_eq!(complexity, 42);
    }

    #[test]
    fn test_cyclomatic_complexity_fallback() {
        let symbol = make_symbol("simple_fn", None);
        let source = r#"
            fn simple_fn(x: i32) -> i32 {
                if x > 0 {
                    return x;
                }
                x * 2
            }
        "#;
        let complexity = MetricsService::cyclomatic_complexity(&symbol, source);
        // 1（入口） + 1（if） = 2
        assert_eq!(complexity, 2);
    }

    #[test]
    fn test_cyclomatic_complexity_minimal() {
        let symbol = make_symbol("minimal", None);
        let source = "fn minimal() {}";
        let complexity = MetricsService::cyclomatic_complexity(&symbol, source);
        assert_eq!(complexity, 1);
    }

    #[test]
    fn test_compute_all_empty() {
        let symbols: Vec<Symbol> = vec![];
        let call_graph = CallGraph::new();
        let type_hierarchy = TypeHierarchy::new();

        let metrics = MetricsService::compute_all(&symbols, &call_graph, &type_hierarchy);
        assert!(metrics.is_empty());
    }

    #[test]
    fn test_compute_all_with_data() {
        let symbols = vec![
            make_symbol("main", Some(3)),
            make_symbol("helper", None),
        ];

        let mut call_graph = CallGraph::new();
        call_graph.add_edge_raw("main", "helper");

        let type_hierarchy = TypeHierarchy::new();

        let metrics = MetricsService::compute_all(&symbols, &call_graph, &type_hierarchy);
        assert_eq!(metrics.len(), 2);

        let main = metrics.iter().find(|m| m.name == "main").unwrap();
        assert_eq!(main.cyclomatic_complexity, 3);
        assert_eq!(main.fan_out, 1); // 调用了 helper
        assert_eq!(main.fan_in, 0);

        let helper = metrics.iter().find(|m| m.name == "helper").unwrap();
        assert_eq!(helper.cyclomatic_complexity, 1); // 默认值
        assert_eq!(helper.fan_in, 1); // 被 main 调用
        assert_eq!(helper.fan_out, 0);
    }
}

//! Git 分支差异比较
//!
//! 使用 git2 库比较两个 Git 引用（分支/标签/commit），
//! 返回变更文件列表及变更类型（新增/修改/删除/重命名）。

use std::path::PathBuf;

use serde::{Deserialize, Serialize};

/// 文件变更类型
///
/// 表示文件在两个引用之间的变更状态。
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum ChangeKind {
    /// 新增文件
    Added,
    /// 修改文件
    Modified,
    /// 删除文件
    Deleted,
    /// 重命名文件（从旧路径到新路径）
    Renamed,
    /// 类型变更（如文件变为目录）
    TypeChanged,
}

/// 变更文件条目
///
/// 描述单个文件在两个 Git 引用之间的变化详情。
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ChangedFile {
    /// 文件路径（相对于仓库根目录）
    pub path: String,
    /// 旧路径（重命名情况下有值）
    pub old_path: Option<String>,
    /// 变更类型
    pub change_kind: ChangeKind,
    /// 是否为二进制文件
    pub is_binary: bool,
}

/// 分支差异结果
///
/// 汇总两个引用之间的所有文件变更。
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BranchDiff {
    /// 源引用名称
    pub from_ref: String,
    /// 目标引用名称
    pub to_ref: String,
    /// 变更文件列表
    pub changed_files: Vec<ChangedFile>,
    /// 新增文件数
    pub added_count: usize,
    /// 修改文件数
    pub modified_count: usize,
    /// 删除文件数
    pub deleted_count: usize,
}

/// 分支差异比较器
///
/// 使用 git2 库比较同一仓库中两个引用之间的差异，
/// 返回结构化的变更文件列表。
pub struct BranchDiffer;

impl BranchDiffer {
    /// 比较两个 Git 引用之间的差异
    ///
    /// 打开指定路径的 Git 仓库，解析两个引用（分支名、标签名或 commit SHA），
    /// 通过 diff 树获取所有变更文件。
    ///
    /// # 参数
    /// - `repo_path` — Git 仓库的本地路径
    /// - `from_ref` — 源引用名称（如 `"main"`, `"HEAD~3"`, `"abc1234"`）
    /// - `to_ref` — 目标引用名称
    ///
    /// # 返回
    /// 包含所有变更文件的差异结果
    ///
    /// # 错误
    /// - 仓库打不开
    /// - 引用无法解析
    /// - diff 计算失败
    pub fn diff(
        repo_path: &str,
        from_ref: &str,
        to_ref: &str,
    ) -> Result<BranchDiff, String> {
        // 打开 Git 仓库
        let repo = git2::Repository::open(repo_path)
            .map_err(|e| format!("无法打开 Git 仓库 '{}': {}", repo_path, e))?;

        // 解析源引用
        let from_commit = Self::resolve_ref(&repo, from_ref)?;
        let from_tree = from_commit
            .tree()
            .map_err(|e| format!("无法获取 '{}' 的树对象: {}", from_ref, e))?;

        // 解析目标引用
        let to_commit = Self::resolve_ref(&repo, to_ref)?;
        let to_tree = to_commit
            .tree()
            .map_err(|e| format!("无法获取 '{}' 的树对象: {}", to_ref, e))?;

        // 计算 diff
        let diff = repo
            .diff_tree_to_tree(
                Some(&from_tree),
                Some(&to_tree),
                None, // 使用默认选项
            )
            .map_err(|e| format!("计算 diff 失败: {}", e))?;

        // 收集变更文件
        let mut changed_files = Vec::new();
        let mut added_count = 0;
        let mut modified_count = 0;
        let mut deleted_count = 0;

        diff.foreach(
            &mut |delta, _progress| {
                let change_kind = match delta.status() {
                    git2::Delta::Added => ChangeKind::Added,
                    git2::Delta::Modified => ChangeKind::Modified,
                    git2::Delta::Deleted => ChangeKind::Deleted,
                    git2::Delta::Renamed => ChangeKind::Renamed,
                    git2::Delta::Typechange => ChangeKind::TypeChanged,
                    _ => ChangeKind::Modified, // 其他类型视为修改
                };

                // 获取新文件路径
                let new_file = delta.new_file();
                let path = new_file
                    .path()
                    .map(|p| p.to_string_lossy().to_string())
                    .unwrap_or_default();

                // 获取旧文件路径（仅重命名时有意义）
                let old_file = delta.old_file();
                let old_path = if delta.status() == git2::Delta::Renamed {
                    old_file
                        .path()
                        .map(|p| p.to_string_lossy().to_string())
                } else {
                    None
                };

                let is_binary = new_file.is_binary();

                let changed_file = ChangedFile {
                    path,
                    old_path,
                    change_kind,
                    is_binary,
                };

                changed_files.push(changed_file);
                true // 继续遍历
            },
            None,
            None,
            None,
            None,
        )
        .map_err(|e| format!("遍历 diff 失败: {}", e))?;

        // 统计各类型数量
        for file in &changed_files {
            match file.change_kind {
                ChangeKind::Added => added_count += 1,
                ChangeKind::Modified => modified_count += 1,
                ChangeKind::Deleted => deleted_count += 1,
                // Renamed 和 TypeChanged 计入 Modified
                _ => modified_count += 1,
            }
        }

        Ok(BranchDiff {
            from_ref: from_ref.to_string(),
            to_ref: to_ref.to_string(),
            changed_files,
            added_count,
            modified_count,
            deleted_count,
        })
    }

    /// 解析 Git 引用为 commit 对象
    ///
    /// 支持分支名、标签名和 commit SHA。
    fn resolve_ref(
        repo: &git2::Repository,
        ref_name: &str,
    ) -> Result<git2::Commit, String> {
        // 尝试直接解析为 Oid（commit SHA）
        if let Ok(oid) = git2::Oid::from_str(ref_name) {
            return repo
                .find_commit(oid)
                .map_err(|e| format!("无法找到 commit '{}': {}", ref_name, e));
        }

        // 尝试作为引用名解析（refs/heads/、refs/tags/、HEAD）
        let reference = repo
            .resolve_reference_from_short_name(ref_name)
            .map_err(|e| format!("无法解析引用 '{}': {}", ref_name, e))?;

        let commit = reference
            .peel_to_commit()
            .map_err(|e| format!("无法将 '{}' 解析为 commit: {}", ref_name, e))?;

        Ok(commit)
    }

    /// 列出两个引用之间的变更文件路径（简化版）
    ///
    /// 返回变更文件的路径列表，不做分类统计。
    /// 适合只需要文件路径列表的场景。
    ///
    /// # 参数
    /// - `repo_path` — Git 仓库的本地路径
    /// - `from_ref` — 源引用名称
    /// - `to_ref` — 目标引用名称
    pub fn list_changed_files(
        repo_path: &str,
        from_ref: &str,
        to_ref: &str,
    ) -> Result<Vec<String>, String> {
        let branch_diff = Self::diff(repo_path, from_ref, to_ref)?;
        Ok(branch_diff
            .changed_files
            .into_iter()
            .map(|f| f.path)
            .collect())
    }
}

//! 符号级差异分析
//!
//! 从文件行级 diff 映射到符号范围，识别受变更影响的符号。
//! 支持 Unified Diff 格式解析和符号范围匹配。

use std::collections::HashMap;
use std::path::PathBuf;

use serde::{Deserialize, Serialize};

/// 变更行范围
///
/// 表示 diff hunk 中发生变更的行号范围。
/// 行号均为 1-based。
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LineRange {
    /// 起始行号（1-based）
    pub start: u64,
    /// 结束行号（1-based）
    pub end: u64,
}

/// 受影响的符号条目
///
/// 描述一个被行级 diff 波及的符号。
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AffectedSymbol {
    /// 符号稳定 ID
    pub symbol_id: String,
    /// 符号名称
    pub name: String,
    /// 符号所在的文件路径
    pub file_path: String,
    /// 符号在文件中的行号范围
    pub line_range: LineRange,
    /// 与 diff 变更行的重叠程度（0.0-1.0，1.0 表示完全在变更范围内）
    pub overlap_ratio: f64,
}

/// 符号范围映射
///
/// 维护文件路径到符号行号范围的映射，
/// 用于将 diff 变更行匹配到具体符号。
pub struct SymbolRangeMap {
    /// 文件路径 → (符号ID, 符号名称, 行号范围) 列表
    file_to_symbols: HashMap<String, Vec<SymbolRangeEntry>>,
}

/// 符号范围条目（内部用）
#[derive(Debug, Clone)]
struct SymbolRangeEntry {
    symbol_id: String,
    name: String,
    line_start: u64,
    line_end: u64,
}

/// 符号差异分析器
///
/// 将行级 diff 映射到符号范围，识别变更影响的符号。
pub struct SymbolDiff;

impl SymbolDiff {
    /// 从 diff 行范围映射到受影响的符号
    ///
    /// 在给定的符号范围映射中，查找与每一行 diff 变更范围有交集的所有符号。
    /// 对于每个受影响的符号，计算变更行与符号定义行的重叠比率。
    ///
    /// # 参数
    /// - `changed_lines` — 文件到变更行号范围的映射
    /// - `symbol_map` — 文件到符号行号范围的映射
    ///
    /// # 返回
    /// 所有受影响的符号列表，按重叠比率降序排列。
    pub fn map_lines_to_symbols(
        changed_lines: &HashMap<String, Vec<LineRange>>,
        symbol_map: &SymbolRangeMap,
    ) -> Vec<AffectedSymbol> {
        let mut affected = Vec::new();

        for (file_path, ranges) in changed_lines {
            // 查找该文件中的所有符号
            if let Some(symbols) = symbol_map.file_to_symbols.get(file_path) {
                for symbol in symbols {
                    // 计算每个符号与 diff 范围的重叠情况
                    let overlap_result =
                        Self::compute_overlap(ranges, symbol.line_start, symbol.line_end);

                    if overlap_result > 0.0 {
                        affected.push(AffectedSymbol {
                            symbol_id: symbol.symbol_id.clone(),
                            name: symbol.name.clone(),
                            file_path: file_path.clone(),
                            line_range: LineRange {
                                start: symbol.line_start,
                                end: symbol.line_end,
                            },
                            overlap_ratio: overlap_result,
                        });
                    }
                }
            }
        }

        // 按重叠比率降序排列（影响最大的在前）
        affected.sort_by(|a, b| {
            b.overlap_ratio
                .partial_cmp(&a.overlap_ratio)
                .unwrap_or(std::cmp::Ordering::Equal)
        });

        affected
    }

    /// 计算变更行范围与符号定义行的重叠比率
    ///
    /// 重叠比率 = 与 diff 有交集的行数 / 符号定义总行数。
    ///
    /// # 返回值
    /// 0.0 到 1.0 之间，其中 1.0 表示符号完全在变更范围内。
    fn compute_overlap(ranges: &[LineRange], symbol_start: u64, symbol_end: u64) -> f64 {
        let symbol_lines = symbol_end - symbol_start + 1;
        if symbol_lines == 0 {
            return 0.0;
        }

        // 检查符号行范围是否与任一 diff hunk 有交集
        let mut has_overlap = false;
        let mut overlap_lines: u64 = 0;

        for range in ranges {
            // 判断两个范围是否相交
            let overlap_start = range.start.max(symbol_start);
            let overlap_end = range.end.min(symbol_end);

            if overlap_start <= overlap_end {
                has_overlap = true;
                overlap_lines += overlap_end - overlap_start + 1;
            }
        }

        if !has_overlap {
            return 0.0;
        }

        // 重叠比率（上限为 1.0）
        (overlap_lines as f64 / symbol_lines as f64).min(1.0)
    }

    /// 解析 Unified Diff 文本，提取文件到变更行范围的映射
    ///
    /// 解析标准 unified diff 格式（如 `git diff` 输出），
    /// 提取每个文件的 hunks 行号范围。
    ///
    /// # 参数
    /// - `diff_text` — unified diff 格式的字符串
    ///
    /// # 返回
    /// `HashMap<文件路径, Vec<变更行范围>>`
    ///
    /// # 注意
    /// 此方法只解析新文件中变更行的范围，适合确定哪些行发生了变更。
    pub fn parse_diff_hunks(diff_text: &str) -> HashMap<String, Vec<LineRange>> {
        let mut result: HashMap<String, Vec<LineRange>> = HashMap::new();
        let mut current_file: Option<String> = None;

        for line in diff_text.lines() {
            // 匹配文件头：`diff --git a/path b/path` 或 `--- a/path`
            if line.starts_with("--- a/") {
                // 提取文件路径（去掉 `--- a/` 前缀）
                current_file = Some(line[6..].to_string());
                continue;
            }

            // 匹配 hunk 头：`@@ -old_start,old_count +new_start,new_count @@`
            if line.starts_with("@@") {
                if let Some(ref file) = current_file {
                    // 解析新文件行号信息
                    if let Some(hunk_range) = Self::parse_hunk_header(line) {
                        result
                            .entry(file.clone())
                            .or_insert_with(Vec::new)
                            .push(hunk_range);
                    }
                }
            }
        }

        result
    }

    /// 解析 hunk 头行
    ///
    /// 格式：`@@ -old_start,old_count +new_start,new_count @@`
    /// 提取新文件的起始行和行数。
    fn parse_hunk_header(header: &str) -> Option<LineRange> {
        // 查找 "+" 后的新文件信息
        let plus_pos = header.rfind('+')?;
        let after_plus = &header[plus_pos + 1..];

        // 提取数字部分（截止到下一个非数字字符或 @@）
        let end_of_num = after_plus
            .find(|c: char| !c.is_ascii_digit())
            .unwrap_or(after_plus.len());
        let num_part = &after_plus[..end_of_num];

        // 格式：start,count 或 start
        if let Some(comma_pos) = num_part.find(',') {
            let start: u64 = num_part[..comma_pos].parse().ok()?;
            let count: u64 = num_part[comma_pos + 1..].parse().ok()?;
            if count > 0 {
                Some(LineRange {
                    start,
                    end: start + count - 1,
                })
            } else {
                // count 为 0 表示空 hunk（如仅有删除），不影响符号匹配
                None
            }
        } else {
            // 只有起始行号（默认 count=1）
            let start: u64 = num_part.parse().ok()?;
            Some(LineRange { start, end: start })
        }
    }
}

// ============================================================================
// SymbolRangeMap 实现
// ============================================================================

impl SymbolRangeMap {
    /// 创建空的符号范围映射
    pub fn new() -> Self {
        Self {
            file_to_symbols: HashMap::new(),
        }
    }

    /// 添加一个符号的行号范围
    ///
    /// # 参数
    /// - `symbol_id` — 符号稳定 ID
    /// - `name` — 符号名称
    /// - `file_path` — 符号所在文件路径
    /// - `line_start` — 符号声明起始行号（1-based）
    /// - `line_end` — 符号声明结束行号（1-based）
    pub fn add_symbol(
        &mut self,
        symbol_id: &str,
        name: &str,
        file_path: &str,
        line_start: u64,
        line_end: u64,
    ) {
        self.file_to_symbols
            .entry(file_path.to_string())
            .or_insert_with(Vec::new)
            .push(SymbolRangeEntry {
                symbol_id: symbol_id.to_string(),
                name: name.to_string(),
                line_start,
                line_end,
            });
    }

    /// 获取映射中的文件数
    pub fn file_count(&self) -> usize {
        self.file_to_symbols.len()
    }

    /// 获取映射中的符号总数
    pub fn symbol_count(&self) -> usize {
        self.file_to_symbols
            .values()
            .map(|v| v.len())
            .sum()
    }
}

impl Default for SymbolRangeMap {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // ========================================================================
    // 行号范围重叠计算测试
    // ========================================================================

    #[test]
    fn test_full_overlap() {
        let ranges = vec![LineRange { start: 10, end: 20 }];
        // 符号行号 12-15 完全在变更范围内
        let ratio = SymbolDiff::compute_overlap(&ranges, 12, 15);
        assert!((ratio - 1.0).abs() < 0.001);
    }

    #[test]
    fn test_partial_overlap() {
        let ranges = vec![LineRange { start: 10, end: 15 }];
        // 符号行号 12-20，前 4 行（12-15）与 diff 重叠
        let ratio = SymbolDiff::compute_overlap(&ranges, 12, 20);
        assert!((ratio - 4.0 / 9.0).abs() < 0.001);
    }

    #[test]
    fn test_no_overlap() {
        let ranges = vec![LineRange { start: 10, end: 15 }];
        // 符号行号 20-30，与 diff 范围无交集
        let ratio = SymbolDiff::compute_overlap(&ranges, 20, 30);
        assert_eq!(ratio, 0.0);
    }

    #[test]
    fn test_multiple_ranges() {
        let ranges = vec![
            LineRange { start: 10, end: 15 },
            LineRange { start: 30, end: 35 },
        ];
        // 符号行号 12-32，与两个 diff hunk 都有重叠
        let ratio = SymbolDiff::compute_overlap(&ranges, 12, 32);
        // 符号总行数: 21
        // 重叠行: (12-15)=4 + (30-32)=3 = 7
        assert!((ratio - 7.0 / 21.0).abs() < 0.001);
    }

    #[test]
    fn test_single_line_symbol() {
        let ranges = vec![LineRange { start: 10, end: 10 }];
        let ratio = SymbolDiff::compute_overlap(&ranges, 10, 10);
        assert!((ratio - 1.0).abs() < 0.001);
    }

    // ========================================================================
    // diff hunk 解析测试
    // ========================================================================

    #[test]
    fn test_parse_hunk_header_with_count() {
        let result = SymbolDiff::parse_hunk_header("@@ -1,5 +1,10 @@");
        assert!(result.is_some());
        let range = result.unwrap();
        assert_eq!(range.start, 1);
        assert_eq!(range.end, 10);
    }

    #[test]
    fn test_parse_hunk_header_without_count() {
        let result = SymbolDiff::parse_hunk_header("@@ -5 +10 @@");
        assert!(result.is_some());
        let range = result.unwrap();
        assert_eq!(range.start, 10);
        assert_eq!(range.end, 10); // 单行
    }

    #[test]
    fn test_parse_hunk_header_context() {
        // 带上下文信息的 hunk
        let result = SymbolDiff::parse_hunk_header("@@ -10,7 +10,6 @@ fn main() {");
        assert!(result.is_some());
        let range = result.unwrap();
        assert_eq!(range.start, 10);
        assert_eq!(range.end, 15);
    }

    // ========================================================================
    // 完整 diff 解析测试
    // ========================================================================

    #[test]
    fn test_parse_diff_hunks_multi_file() {
        let diff_text = r#"diff --git a/src/main.rs b/src/main.rs
--- a/src/main.rs
+++ b/src/main.rs
@@ -1,3 +1,5 @@ fn main() {
 fn main() {
+    println!("hello");
 }

diff --git a/src/lib.rs b/src/lib.rs
--- a/src/lib.rs
+++ b/src/lib.rs
@@ -10,0 +11,5 @@ pub fn add(a: i32, b: i32) -> i32 {
+pub fn add(a: i32, b: i32) -> i32 {
+    a + b
+}
+
"#;

        let result = SymbolDiff::parse_diff_hunks(diff_text);

        // src/main.rs 应该有一个 hunk
        assert!(result.contains_key("src/main.rs"));
        let main_ranges = &result["src/main.rs"];
        assert_eq!(main_ranges.len(), 1);
        assert_eq!(main_ranges[0].start, 1);
        assert_eq!(main_ranges[0].end, 5);

        // src/lib.rs 应该有一个 hunk
        assert!(result.contains_key("src/lib.rs"));
        let lib_ranges = &result["src/lib.rs"];
        assert_eq!(lib_ranges.len(), 1);
        assert_eq!(lib_ranges[0].start, 11);
        assert_eq!(lib_ranges[0].end, 15);
    }

    #[test]
    fn test_parse_diff_empty() {
        let result = SymbolDiff::parse_diff_hunks("");
        assert!(result.is_empty());
    }

    // ========================================================================
    // 符号范围映射测试
    // ========================================================================

    #[test]
    fn test_symbol_range_map_basic() {
        let mut map = SymbolRangeMap::new();
        assert_eq!(map.file_count(), 0);
        assert_eq!(map.symbol_count(), 0);

        map.add_symbol("id_main", "main", "src/main.rs", 1, 5);
        map.add_symbol("id_helper", "helper", "src/main.rs", 10, 15);
        map.add_symbol("id_init", "init", "src/lib.rs", 1, 3);

        assert_eq!(map.file_count(), 2); // main.rs 和 lib.rs
        assert_eq!(map.symbol_count(), 3);
    }

    #[test]
    fn test_map_lines_to_symbols() {
        // 构建符号范围映射
        let mut map = SymbolRangeMap::new();
        map.add_symbol("id_main", "main", "src/main.rs", 1, 10);
        map.add_symbol("id_helper", "helper", "src/main.rs", 20, 25);
        map.add_symbol("id_util", "util", "src/util.rs", 5, 15);

        // 构建变更行映射
        let mut changed_lines = HashMap::new();
        changed_lines.insert(
            "src/main.rs".to_string(),
            vec![
                LineRange { start: 1, end: 5 },    // 与 main 重叠
            ],
        );
        changed_lines.insert(
            "src/util.rs".to_string(),
            vec![
                LineRange { start: 10, end: 12 },  // 与 util 重叠
            ],
        );

        let affected = SymbolDiff::map_lines_to_symbols(&changed_lines, &map);

        // main 和 util 受影响
        assert_eq!(affected.len(), 2);

        let main_affected = affected.iter().find(|s| s.name == "main").unwrap();
        assert!(main_affected.overlap_ratio > 0.0);
        assert_eq!(main_affected.file_path, "src/main.rs");

        let util_affected = affected.iter().find(|s| s.name == "util").unwrap();
        assert!(util_affected.overlap_ratio > 0.0);
        assert_eq!(util_affected.file_path, "src/util.rs");

        // helper 不受影响
        assert!(affected.iter().all(|s| s.name != "helper"));
    }

    #[test]
    fn test_map_lines_to_symbols_no_overlap() {
        let mut map = SymbolRangeMap::new();
        map.add_symbol("id_main", "main", "src/main.rs", 1, 10);

        let mut changed_lines = HashMap::new();
        changed_lines.insert(
            "src/main.rs".to_string(),
            vec![LineRange { start: 50, end: 60 }],
        );

        let affected = SymbolDiff::map_lines_to_symbols(&changed_lines, &map);
        assert!(affected.is_empty());
    }

    #[test]
    fn test_map_lines_to_symbols_sorted() {
        let mut map = SymbolRangeMap::new();
        map.add_symbol("id_a", "func_a", "src/lib.rs", 1, 10);
        map.add_symbol("id_b", "func_b", "src/lib.rs", 20, 25);

        let mut changed_lines = HashMap::new();
        changed_lines.insert(
            "src/lib.rs".to_string(),
            vec![
                LineRange { start: 3, end: 5 },   // func_a 部分重叠
                LineRange { start: 20, end: 25 }, // func_b 完全重叠
            ],
        );

        let affected = SymbolDiff::map_lines_to_symbols(&changed_lines, &map);

        // 按重叠比率降序排列，func_b (1.0) 应在 func_a (0.3) 之前
        assert_eq!(affected.len(), 2);
        assert!(affected[0].overlap_ratio >= affected[1].overlap_ratio);
    }
}

